def kruskal(graph, n):
    edges = []
    for u, v, w in graph:
        edges.append((w, u, v))

    edges.sort()
    parent = list(range(n + 1))
    rank = [0] * (n + 1)
    mst_edges = []

    for weight, u, v in edges:
        if find(parent, u) != find(parent, v):
            union(parent, rank, u, v)
            mst_edges.append((u, v, weight))

    return mst_edges

def min_operations_to_unify_mst(n, m, edges, k):
    graph = []
