        graph.append((u, v, w))

    mst_edges = kruskal(graph, n)
    mst_cost = sum(w for _, _, w in mst_edges)

    if mst_cost != k:
        return -1

    unique_mst_count = 0
    operations = 0

    for u, v, w in edges:
